"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[93622],{17547:(a,s,e)=>{e.r(s),e.d(s,{data:()=>i});const i={key:"v-45c76692",path:"/ArcGIS/ArcMap/%E5%9C%86%E5%BC%A7%E5%AF%BC%E8%87%B4shp%E9%9D%A2%E7%A7%AF%E8%AF%AF%E5%B7%AE%E8%A7%A3%E5%86%B3%E5%8A%9E%E6%B3%95.html",title:"圆弧导致shp面积误差解决办法",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"一问题描述:",slug:"一问题描述",children:[]},{level:2,title:"二问题分析:",slug:"二问题分析",children:[]},{level:2,title:"三解决办法:",slug:"三解决办法",children:[]},{level:2,title:"四结果:",slug:"四结果",children:[]},{level:2,title:"",slug:"",children:[]}],git:{updatedTime:1653445943e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"ArcGIS/ArcMap/圆弧导致shp面积误差解决办法.md"}},50181:(a,s,e)=>{e.r(s),e.d(s,{default:()=>t});const i=(0,e(57293).uE)('<h1 id="圆弧导致shp面积误差解决办法" tabindex="-1"><a class="header-anchor" href="#圆弧导致shp面积误差解决办法" aria-hidden="true">#</a> 圆弧导致shp面积误差解决办法</h1><h2 id="一问题描述" tabindex="-1"><a class="header-anchor" href="#一问题描述" aria-hidden="true">#</a> <strong>一问题描述</strong>:</h2><p>原始数据是2000投影坐标系,转为2000地理坐标系后面积出现误差</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032038033.jpg" alt="img"></p><h2 id="二问题分析" tabindex="-1"><a class="header-anchor" href="#二问题分析" aria-hidden="true">#</a> <strong>二问题分析</strong>:</h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032038034.jpg" alt="img"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032038035.jpg" alt="img"></p><p>经过分析,发现源数据的圆弧在经过投影转换之后,弧变成多个线段组成,线段点不够多,所以出现了误差</p><h2 id="三解决办法" tabindex="-1"><a class="header-anchor" href="#三解决办法" aria-hidden="true">#</a> <strong>三解决办法:</strong></h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032038036.jpg" alt="img"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032038037.jpg" alt="img"></p><p>(1) 选择angle模式(根据角度增密度),如果选择其他模式容易出现直线段也增密,导致点数量过多。</p><p>(2) 最大偏转角度请选择合适的数值(根据实际数据为准),否则容易出现点数量过多</p><p>对源数据使用arcgis增密方法,增加点的密度,减少误差</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032038038.jpg" alt="img"></p><p>原始数据</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032038039.jpg" alt="img"></p><p>增密后数据</p><h2 id="四结果" tabindex="-1"><a class="header-anchor" href="#四结果" aria-hidden="true">#</a> <strong>四结果:</strong></h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202111032038040.jpg" alt="img"></p><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h2>',21),h={},t=(0,e(63243).Z)(h,[["render",function(a,s){return i}]])},63243:(a,s)=>{s.Z=(a,s)=>{const e=a.__vccOpts||a;for(const[a,i]of s)e[a]=i;return e}}}]);